// // This module implements a 2-to-1 multiplexer that selects between inputs B and A based on the state of the select line S
module top_module(A, B, S, Z);input A, B, S;
output reg Z; // Change output Z to reg type

  // Behavioral modeling
  always @ (A, B, S)
    if (S == 0)
      Z = A;
    else
      Z = B;

endmodule
